-- DC local clubs (24 clubs -> 68 weekly instances) as recurring community events.
-- Each club recurs on its primary meeting day across the discovery window; the
-- feed collapses repeats to one card (dedupeFeedEvents). DC-forward address +
-- neighborhood keep them past the enforce-dc trigger and the client DC filter.
-- Paste into Supabase -> SQL Editor -> Run. Safe to re-run.
begin;
delete from public.events where source = 'dc-clubs';
commit;
